namespace sv_86fcb8e6707a4e778e898eeb6ef29207;

public class JobHistoryEntry
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public string Years { get; set; } = "";
}

public class ReferenceContact
{
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";
    public string Relationship { get; set; } = "";
}

/// <summary>
/// Scoped service that holds wizard data for the lifetime of a circuit.
/// On Blazor Server, scoped = per circuit = per user, so each applicant
/// gets their own independent instance.
/// </summary>
public class WizardState
{
    // Step 1 — Personal Info
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";

    // Step 2 — Experience
    public List<JobHistoryEntry> JobHistory { get; set; } = [new()];

    // Step 3 — References
    public List<ReferenceContact> References { get; set; } = [new()];

    // Track which steps have been explicitly saved
    public HashSet<int> CompletedSteps { get; } = [];
}

@inject NavigationManager Nav

@{
    var steps = new (string Href, string Label)[]
    {
        ("apply/personal-info", "Personal Info"),
        ("apply/experience",    "Experience"),
        ("apply/references",    "References"),
        ("apply/review",        "Review"),
    };

    var uri = Nav.ToBaseRelativePath(Nav.Uri).TrimEnd('/').ToLowerInvariant();
    int current = -1;
    for (int i = 0; i < steps.Length; i++)
    {
        if (uri == steps[i].Href)
        {
            current = i;
            break;
        }
    }
}

@if (current >= 0)
{
    <nav class="wizard-progress mb-3 d-flex align-items-center gap-2 px-4 py-2 bg-light border-bottom">
        <strong class="me-2">Step @(current + 1) of @steps.Length</strong>
        @for (int i = 0; i < steps.Length; i++)
        {
            var step = steps[i];
            var css = i == current ? "badge bg-primary" : i < current ? "badge bg-success" : "badge bg-secondary";
            <a href="@step.Href" class="@css text-decoration-none">@step.Label</a>
        }
    </nav>
}

@page "/apply/personal-info"
@rendermode InteractiveServer
@inject WizardState Wizard
@inject NavigationManager Nav

<PageTitle>Apply — Personal Info</PageTitle>

<h1>Step 1: Personal Info</h1>

<EditForm Model="Wizard" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="Wizard.FullName" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="Wizard.Email" />
    </div>
    <button type="submit" class="btn btn-primary">Next &rarr;</button>
</EditForm>

@code {
    private void Next()
    {
        Wizard.CompletedSteps.Add(1);
        Nav.NavigateTo("apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@inject WizardState Wizard
@inject NavigationManager Nav

<PageTitle>Apply — Experience</PageTitle>

<h1>Step 2: Experience</h1>

@for (int i = 0; i < Wizard.JobHistory.Count; i++)
{
    var entry = Wizard.JobHistory[i];
    <div class="card mb-3 p-3">
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="entry.Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Job Title</label>
            <input class="form-control" @bind="entry.Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input class="form-control" @bind="entry.Years" />
        </div>
        @if (Wizard.JobHistory.Count > 1)
        {
            var idx = i;
            <button class="btn btn-sm btn-outline-danger" @onclick="() => Wizard.JobHistory.RemoveAt(idx)">Remove</button>
        }
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">+ Add another</button>

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick='() => Nav.NavigateTo("apply/personal-info")'>&larr; Back</button>
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private void AddEntry() => Wizard.JobHistory.Add(new());

    private void Next()
    {
        Wizard.CompletedSteps.Add(2);
        Nav.NavigateTo("apply/references");
    }
}

@page "/apply/references"
@rendermode InteractiveServer
@inject WizardState Wizard
@inject NavigationManager Nav

<PageTitle>Apply — References</PageTitle>

<h1>Step 3: References</h1>

@for (int i = 0; i < Wizard.References.Count; i++)
{
    var contact = Wizard.References[i];
    <div class="card mb-3 p-3">
        <div class="mb-2">
            <label class="form-label">Name</label>
            <input class="form-control" @bind="contact.Name" />
        </div>
        <div class="mb-2">
            <label class="form-label">Email</label>
            <input class="form-control" @bind="contact.Email" />
        </div>
        <div class="mb-2">
            <label class="form-label">Relationship</label>
            <input class="form-control" @bind="contact.Relationship" />
        </div>
        @if (Wizard.References.Count > 1)
        {
            var idx = i;
            <button class="btn btn-sm btn-outline-danger" @onclick="() => Wizard.References.RemoveAt(idx)">Remove</button>
        }
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddRef">+ Add another</button>

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick='() => Nav.NavigateTo("apply/experience")'>&larr; Back</button>
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private void AddRef() => Wizard.References.Add(new());

    private void Next()
    {
        Wizard.CompletedSteps.Add(3);
        Nav.NavigateTo("apply/review");
    }
}

@page "/apply/review"
@rendermode InteractiveServer
@inject WizardState Wizard
@inject NavigationManager Nav

<PageTitle>Apply — Review</PageTitle>

<h1>Step 4: Review Your Application</h1>

<div class="card mb-3 p-3">
    <h5>Personal Info</h5>
    <p><strong>Name:</strong> @Wizard.FullName</p>
    <p><strong>Email:</strong> @Wizard.Email</p>
    <a href="apply/personal-info" class="btn btn-sm btn-outline-primary">Edit</a>
</div>

<div class="card mb-3 p-3">
    <h5>Experience</h5>
    @foreach (var job in Wizard.JobHistory)
    {
        <p>@job.Title at @job.Company (@job.Years)</p>
    }
    <a href="apply/experience" class="btn btn-sm btn-outline-primary">Edit</a>
</div>

<div class="card mb-3 p-3">
    <h5>References</h5>
    @foreach (var r in Wizard.References)
    {
        <p>@r.Name — @r.Email (@r.Relationship)</p>
    }
    <a href="apply/references" class="btn btn-sm btn-outline-primary">Edit</a>
</div>

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick='() => Nav.NavigateTo("apply/references")'>&larr; Back</button>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@if (_submitted)
{
    <div class="alert alert-success mt-3">Application submitted successfully!</div>
}

@code {
    private bool _submitted;

    private void Submit()
    {
        Wizard.CompletedSteps.Add(4);
        _submitted = true;
    }
}

