toolArgs.file_text:
@inject NavigationManager Nav

@{
    var steps = new (string Href, string Label)[]
    {
        ("apply/personal-info", "Personal Info"),
        ("apply/experience",    "Experience"),
        ("apply/references",    "References"),
        ("apply/review",        "Review"),
    };

    var uri = Nav.ToBaseRelativePath(Nav.Uri).TrimEnd('/').ToLowerInvariant();
    int current = -1;
    for (int i = 0; i < steps.Length; i++)
    {
        if (uri == steps[i].Href)
        {
            current = i;
            break;
        }
    }
}

@if (current >= 0)
{
    <nav class="wizard-progress mb-3 d-flex align-items-center gap-2 px-4 py-2 bg-light border-bottom">
        <strong class="me-2">Step @(current + 1) of @steps.Length</strong>
        @for (int i = 0; i < steps.Length; i++)
        {
            var step = steps[i];
            var css = i == current ? "badge bg-primary" : i < current ? "badge bg-success" : "badge bg-secondary";
            <a href="@step.Href" class="@css text-decoration-none">@step.Label</a>
        }
    </nav>
}

