@page "/apply/personal-info"
@rendermode InteractiveServer
@inject WizardState Wizard
@inject NavigationManager Nav

<PageTitle>Apply — Personal Info</PageTitle>

<h1>Step 1: Personal Info</h1>

<EditForm Model="Wizard" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="Wizard.FullName" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="Wizard.Email" />
    </div>
    <button type="submit" class="btn btn-primary">Next &rarr;</button>
</EditForm>

@code {
    private void Next()
    {
        Wizard.CompletedSteps.Add(1);
        Nav.NavigateTo("apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@inject WizardState Wizard
@inject NavigationManager Nav

<PageTitle>Apply — Experience</PageTitle>

<h1>Step 2: Experience</h1>

@for (int i = 0; i < Wizard.JobHistory.Count; i++)
{
    var entry = Wizard.JobHistory[i];
    <div class="card mb-3 p-3">
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="entry.Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Job Title</label>
            <input class="form-control" @bind="entry.Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input class="form-control" @bind="entry.Years" />
        </div>
        @if (Wizard.JobHistory.Count > 1)
        {
            var idx = i;
            <button class="btn btn-sm btn-outline-danger" @onclick="() => Wizard.JobHistory.RemoveAt(idx)">Remove</button>
        }
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">+ Add another</button>

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick='() => Nav.NavigateTo("apply/personal-info")'>&larr; Back</button>
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private void AddEntry() => Wizard.JobHistory.Add(new());

    private void Next()
    {
        Wizard.CompletedSteps.Add(2);
        Nav.NavigateTo("apply/references");
    }
}

@page "/apply/references"
@rendermode InteractiveServer
@inject WizardState Wizard
@inject NavigationManager Nav

<PageTitle>Apply — References</PageTitle>

<h1>Step 3: References</h1>

@for (int i = 0; i < Wizard.References.Count; i++)
{
    var contact = Wizard.References[i];
    <div class="card mb-3 p-3">
        <div class="mb-2">
            <label class="form-label">Name</label>
            <input class="form-control" @bind="contact.Name" />
        </div>
        <div class="mb-2">
            <label class="form-label">Email</label>
            <input class="form-control" @bind="contact.Email" />
        </div>
        <div class="mb-2">
            <label class="form-label">Relationship</label>
            <input class="form-control" @bind="contact.Relationship" />
        </div>
        @if (Wizard.References.Count > 1)
        {
            var idx = i;
            <button class="btn btn-sm btn-outline-danger" @onclick="() => Wizard.References.RemoveAt(idx)">Remove</button>
        }
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddRef">+ Add another</button>

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick='() => Nav.NavigateTo("apply/experience")'>&larr; Back</button>
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private void AddRef() => Wizard.References.Add(new());

    private void Next()
    {
        Wizard.CompletedSteps.Add(3);
        Nav.NavigateTo("apply/review");
    }
}

@page "/apply/review"
