    @foreach (var job in Wizard.JobHistory)
    {
        <p>@job.Title at @job.Company (@job.Years)</p>
    }
    <a href="apply/experience" class="btn btn-sm btn-outline-primary">Edit</a>
</div>

<div class="card mb-3 p-3">
    <h5>References</h5>
    @foreach (var r in Wizard.References)
    {
        <p>@r.Name — @r.Email (@r.Relationship)</p>
    }
    <a href="apply/references" class="btn btn-sm btn-outline-primary">Edit</a>
</div>

<div class="d-flex gap-2">
